param([string]$FixturePath='examples/r5-h3-radar-object-fixtures/fixtures.json',[string]$ReportPath='state/checks/r5-h3-radar-objects-report.json')
$ErrorActionPreference='Stop';. (Join-Path $PSScriptRoot 'WindowsRuntimeHelper.ps1')
function Test-R5H3($c){$e=[Collections.Generic.List[string]]::new();$p=$c.event.event_fingerprint;foreach($x in @('subject','action','time_window','location','business_chain')){if([string]::IsNullOrWhiteSpace([string]$p.$x)){$e.Add("fingerprint_missing:$x")}};if($c.candidate.event_id -ne $c.event.event_id){$e.Add('candidate_event_mismatch')};if($c.candidate.used_car_directness -eq 'spillover_proven' -and [string]::IsNullOrWhiteSpace([string]$c.candidate.spillover_proof)){$e.Add('spillover_proof_missing')};foreach($s in @($c.signals)){if($s.discovery_mode -eq 'manual_watchlist' -and [string]::IsNullOrWhiteSpace([string]$s.watchlist_reason)){$e.Add('watchlist_reason_missing')}};$sn=@($c.snapshots);foreach($s in $sn){if($s.trend_status -in @('rising','sustained','cooling')){if($sn.Count -lt 2 -or [string]::IsNullOrWhiteSpace([string]$s.comparison_basis)){$e.Add('trend_requires_two_comparable_snapshots')}}};return @($e)}
try{$root=Split-Path -Parent $PSScriptRoot;$path=if([IO.Path]::IsPathRooted($FixturePath)){$FixturePath}else{Join-Path $root $FixturePath};$f=Get-Content $path -Raw -Encoding UTF8|ConvertFrom-Json;$rows=[Collections.Generic.List[object]]::new();foreach($c in @($f.cases)){$e=@(Test-R5H3 $c);$a=if($e.Count){'fail'}else{'pass'};$rows.Add([ordered]@{fixture_id=$c.fixture_id;expected_result=$c.expected_result;actual_result=$a;expectation_met=($a -eq $c.expected_result);errors=$e})};$bad=@($rows|?{-not $_.expectation_met});$report=[ordered]@{schema_id='taoge://reports/r5/h3/v0.1';overall_result=$(if($bad.Count){'fail'}else{'pass'});case_count=$rows.Count;failure_count=$bad.Count;results=@($rows)};$out=if([IO.Path]::IsPathRooted($ReportPath)){$ReportPath}else{Join-Path $root $ReportPath};Write-TaogeUtf8NoBomJson -Path $out -Value $report -Depth 10;"R5_H3_RADAR_OBJECTS_CHECK=$($report.overall_result)";"CASE_COUNT=$($report.case_count)";if($bad.Count){exit 1}}catch{Write-Error $_;exit 3}
